import{_ as o,b0 as a,aC as e,aF as p}from"./chunks/framework.DMsx7SBw.js";const M=JSON.parse('{"title":"LLMOps","description":"","frontmatter":{"title":"LLMOps","order":50},"headers":[],"relativePath":"ai/app/overlay/ops/index.md","filePath":"ai/app/overlay/ops/index.md"}'),r={name:"ai/app/overlay/ops/index.md"};function s(n,t,i,L,l,d){return a(),e("div",null,[...t[0]||(t[0]=[p('<h1 id="llmops" tabindex="-1">LLMOps <a class="header-anchor" href="#llmops" aria-label="Permalink to “LLMOps”">​</a></h1><p>LLM 应用上线后最大的挑战是&quot;怎么知道它答得好不好&quot;。传统软件可以通过单元测试验证正确性，但 LLM 的输出是概率性的——同样的输入可能产生不同的输出，且输出质量是主观的。LLMOps 借鉴 MLOps 的思路，构建了评估、测试、观测的生产闭环，让 LLM 应用从&quot;能跑的 demo&quot;进化为&quot;可信赖的生产系统&quot;。</p><h2 id="三大支柱" tabindex="-1">三大支柱 <a class="header-anchor" href="#三大支柱" aria-label="Permalink to “三大支柱”">​</a></h2><p>LLMOps 由三个相互支撑的环节组成：</p><p><strong>评估</strong>（Evaluation）回答&quot;好不好&quot;的问题。通过评估框架、评估数据集和评估指标，量化 LLM 应用的输出质量。评估是迭代的起点——不知道当前效果如何，就无法判断改进是否有效。</p><p><strong>测试</strong>（Testing）回答&quot;会不会退步&quot;的问题。Prompt 修改、模型升级、数据更新都可能引入回归。自动化测试流水线确保每次变更都有质量保障，不会让已解决的问题重现。</p><p><strong>观测</strong>（Observability）回答&quot;线上怎么样&quot;的问题。全链路追踪记录每次请求的完整路径，成本追踪监控 Token 消耗和费用，性能监控关注延迟和吞吐量。观测数据驱动评估和测试的持续改进。</p><h2 id="与传统-mlops-的区别" tabindex="-1">与传统 MLOps 的区别 <a class="header-anchor" href="#与传统-mlops-的区别" aria-label="Permalink to “与传统 MLOps 的区别”">​</a></h2><p>LLMOps 和传统 MLOps 有关键差异。传统 ML 模型的输出是确定性的（分类标签、回归数值），评估指标明确（准确率、F1、RMSE）。LLM 的输出是非确定性的自然语言，评估需要处理&quot;多种正确答案&quot;和&quot;质量的主观性&quot;。</p><p>传统 ML 的部署是一次性的（训练→部署→服务），LLM 的部署是持续的（Prompt 迭代、模型切换、数据更新）。每次 Prompt 修改都相当于一次&quot;模型更新&quot;，需要完整的测试和验证流程。</p><p>传统 ML 的监控关注数据漂移和模型退化，LLM 的监控还需要关注成本（Token 消耗可能意外暴增）、安全（Prompt 注入攻击）和合规（输出内容审查）。</p>',11)])])}const m=o(r,[["render",s]]);export{M as __pageData,m as default};
